#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    vector<int> unionOfArrays(vector<int>& nums1, vector<int>& nums2) {
        set<int> s;
        for (int num : nums1) s.insert(num);
        for (int num : nums2) s.insert(num);
        vector<int> res(s.begin(), s.end());
        sort(res.begin(), res.end());
        return res;
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m;
    cin >> m;
    vector<int> nums1(m);
    for (int i = 0; i < m; i++) cin >> nums1[i];
    int n;
    cin >> n;
    vector<int> nums2(n);
    for (int i = 0; i < n; i++) cin >> nums2[i];
    Solution sol;
    vector<int> ans = sol.unionOfArrays(nums1, nums2);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
